    10→
    11→pub async fn reap_orphans(
    12→    running_dir: &Path,
    13→    pending_dir: &Path,
    14→    failed_dir: &Path,
    15→    max_retries: u32,
    16→    stale_lease_after: Duration,
    17→) -> anyhow::Result<()> {
    18→    let stale_after_chrono =
    19→        ChronoDuration::from_std(stale_lease_after).unwrap_or_else(|_| ChronoDuration::seconds(30));
    20→    let entries = match fs::read_dir(running_dir) {
    21→        Ok(e) => e,
    22→        Err(_) => return Ok(()),
    23→    };
    24→
    25→    for ent in entries.flatten() {
    26→        let card_dir = ent.path();
    27→        if !card_dir.is_dir() {
    28→            continue;
    29→        }
    30→        if card_dir.extension().and_then(|s| s.to_str()).unwrap_or("") != "bop" {
    31→            continue;
    32→        }
    33→
    34→        let pid = read_pid(&card_dir).await?;
    35→        let pid_dead = match pid {
    36→            Some(pid) => !is_alive(pid).await?,
    37→            None => false,
    38→        };
    39→        let lease = lock::read_run_lease(&card_dir);
    40→        let lease_stale = lease
    41→            .as_ref()
    42→            .map(|l| lock::lease_is_stale(l, stale_after_chrono))
    43→            .unwrap_or(false);
    44→        if !pid_dead && !lease_stale {
    45→            continue;
    46→        }
    47→
    48→        let mut meta = bop_core::read_meta(&card_dir).ok();
    49→        let retry_count = meta.as_ref().and_then(|m| m.retry_count).unwrap_or(0);
    50→        let next_retry = retry_count.saturating_add(1);
    51→        let move_to_failed = next_retry > max_retries;
    52→        if let Some(ref mut m) = meta {
    53→            m.retry_count = Some(next_retry);
    54→            if move_to_failed {
    55→                m.failure_reason = Some("max_retries_exceeded".to_string());
    56→            } else {
    57→                m.failure_reason = None;
    58→            }
    59→            for stage in m.stages.values_mut() {
    60→                if stage.status == StageStatus::Running {
    61→                    stage.status = if move_to_failed {
    62→                        StageStatus::Failed
    63→                    } else {
    64→                        StageStatus::Pending
    65→                    };
    66→                    stage.agent = None;
    67→                    stage.provider = None;
    68→                    stage.duration_s = None;
    69→                    stage.started = None;
    70→                    stage.blocked_by = None;
    71→                }
    72→            }
    73→            let _ = write_meta(&card_dir, m);
    74→        }
    75→
    76→        let name = match card_dir.file_name().and_then(|s| s.to_str()) {
    77→            Some(n) => n.to_string(),
    78→            None => continue,
    79→        };
    80→        let target = if move_to_failed {
    81→            failed_dir.join(&name)
    82→        } else {
    83→            pending_dir.join(&name)
    84→        };
    85→        let _ = fs::rename(&card_dir, &target);
    86→        quicklook::render_card_thumbnail(&target);
    87→    }
    88→
    89→    Ok(())
    90→}
