    92→pub async fn read_pid(card_dir: &Path) -> anyhow::Result<Option<i32>> {
    93→    let out = TokioCommand::new("xattr")
    94→        .arg("-p")
    95→        .arg("sh.bop.agent-pid")
    96→        .arg(card_dir)
    97→        .output()
    98→        .await;
    99→    if let Ok(out) = out {
   100→        if out.status.success() {
   101→            if let Ok(s) = String::from_utf8(out.stdout) {
   102→                if let Ok(pid) = s.trim().parse::<i32>() {
   103→                    return Ok(Some(pid));
   104→                }
   105→            }
   106→        }
   107→    }
   108→
   109→    let pid_path = card_dir.join("logs").join("pid");
   110→    if let Ok(s) = fs::read_to_string(pid_path) {
   111→        if let Ok(pid) = s.trim().parse::<i32>() {
   112→            return Ok(Some(pid));
   113→        }
   114→    }
   115→
   116→    if let Some(lease) = lock::read_run_lease(card_dir) {
   117→        return Ok(Some(lease.pid));
   118→    }
   119→
   120→    Ok(None)
   121→}
