   132→pub async fn recover_orphans(
   133→    running_dir: &Path,
   134→    pending_dir: &Path,
   135→) -> anyhow::Result<Vec<String>> {
   136→    let mut recovered = Vec::new();
   137→    let entries = match fs::read_dir(running_dir) {
   138→        Ok(e) => e,
   139→        Err(_) => return Ok(recovered),
   140→    };
   141→
   142→    for ent in entries.flatten() {
   143→        let card_dir = ent.path();
   144→        if !card_dir.is_dir() {
   145→            continue;
   146→        }
   147→        if card_dir.extension().and_then(|s| s.to_str()).unwrap_or("") != "bop" {
   148→            continue;
   149→        }
   150→
   151→        let pid = read_pid(&card_dir).await?;
   152→        let pid_dead = match pid {
   153→            Some(pid) => !is_alive(pid).await?,
   154→            None => true, // No PID means orphaned
   155→        };
   156→
   157→        if !pid_dead {
   158→            continue;
   159→        }
   160→
   161→        // Try to read meta.json, create minimal one if corrupt/missing
   162→        let meta = match bop_core::read_meta(&card_dir) {
   163→            Ok(m) => m,
   164→            Err(_) => {
   165→                // Corrupt or missing meta.json - create minimal recovery meta
   166→                let id = card_dir
   167→                    .file_stem()
   168→                    .and_then(|s| s.to_str())
   169→                    .unwrap_or("unknown")
   170→                    .to_string();
   171→                let minimal_meta = bop_core::Meta {
   172→                    id: id.clone(),
   173→                    stage: "pending".to_string(),
   174→                    ..Default::default()
   175→                };
   176→                let _ = bop_core::write_meta(&card_dir, &minimal_meta);
   177→                minimal_meta
   178→            }
   179→        };
   180→
   181→        let name = match card_dir.file_name().and_then(|s| s.to_str()) {
   182→            Some(n) => n.to_string(),
   183→            None => continue,
   184→        };
   185→        let target = pending_dir.join(&name);
   186→        let _ = fs::rename(&card_dir, &target);
   187→        quicklook::render_card_thumbnail(&target);
   188→        recovered.push(meta.id);
   189→    }
   190→
   191→    Ok(recovered)
   192→}
